const raw = $input.item.json;
const paper = raw.body ?? raw;
const apiKey = $env.OPENAI_API_KEY;

const paperId = paper.paper_id || '';
const title = paper.title || '';
const paperText = paper.paper_text || '';

const data = await this.helpers.request({
  method: 'POST',
  uri: 'https://api.openai.com/v1/chat/completions',
  headers: { 'Authorization': 'Bearer ' + apiKey },
  body: {
    model: 'gpt-4o-mini',
    max_tokens: 1500,
    messages: [
      { role: 'system', content: 'You are a careful academic reader. When given a paper, produce a structured summary with these clearly labelled sections:\n\n## Problem & Motivation\n## Proposed Method\n## Methods\n## Results\n## Claimed Contributions\n\nBe factual and concise. Include specific numbers from experiments.' },
      { role: 'user', content: 'Please summarise the following paper:\n\nTitle: ' + title + '\n\n' + paperText }
    ]
  },
  json: true
});

const summary = data.choices[0].message.content;

return [{ json: { paper_id: paperId, title: title, paper_text: paperText, reader_summary: summary } }];

const raw = $input.item.json;
const ctx = raw.body ?? raw;
const apiKey = $env.OPENAI_API_KEY;
const paperText = ctx.paper_text || '';

const data = await this.helpers.request({
  method: 'POST',
  uri: 'https://api.openai.com/v1/chat/completions',
  headers: { 'Authorization': 'Bearer ' + apiKey },
  body: {
    model: 'gpt-4o',
    max_tokens: 1200,
    messages: [
      { role: 'system', content: 'You are a rigorous peer reviewer for a top-tier ML/AI venue. Given a paper and its summary, identify substantive weaknesses in: novelty, methodology, evaluation, clarity, and reproducibility. For each point give: (a) the issue, (b) why it matters, (c) what specific evidence from the paper supports your concern. Be specific and cite details from the paper.' },
      { role: 'user', content: 'Paper title: ' + (ctx.title || '') + '\n\nPaper text:\n' + paperText + '\n\nReader summary:\n' + (ctx.reader_summary || '') + '\n\nNow list your critique points.' }
    ]
  },
  json: true
});

const critique = data.choices[0].message.content;

return [{ json: { ...ctx, critic_points: critique } }];

const raw = $input.item.json;
const ctx = raw.body ?? raw;
const apiKey = $env.OPENAI_API_KEY;
const paperText = ctx.paper_text || '';

const data = await this.helpers.request({
  method: 'POST',
  uri: 'https://api.openai.com/v1/chat/completions',
  headers: { 'Authorization': 'Bearer ' + apiKey },
  body: {
    model: 'gpt-4o-mini',
    max_tokens: 1000,
    messages: [
      { role: 'system', content: 'You are a senior programme committee member auditing a peer review. Challenge critique points that are vague, generic, or unsupported by the paper. Require concrete evidence from the paper text or summary. If a point cannot be tied to specific content, say it should be removed or rewritten. Also identify important paper-level weaknesses the Critic missed. Do not discuss the quality of the debate itself except to demand grounding in the paper.' },
      { role: 'user', content: 'Paper title: ' + (ctx.title || '') + '\n\nPaper text:\n' + paperText + '\n\nPaper summary:\n' + (ctx.reader_summary || '') + '\n\nCritic points:\n' + (ctx.critic_points || '') + '\n\nAudit the critique. For each weak point, explain what evidence is missing. Then list any important missed weaknesses that are actually grounded in the paper.' }
    ]
  },
  json: true
});

const auditFeedback = data.choices[0].message.content;

return [{ json: { ...ctx, auditor_feedback: auditFeedback } }];

const raw = $input.item.json;
const ctx = raw.body ?? raw;
const apiKey = $env.OPENAI_API_KEY;
const paperText = ctx.paper_text || '';

const schema = '{"summary":"<2-3 sentence summary>","strengths":[{"point":"<strength>","evidence":"<evidence>"}],"weaknesses":[{"point":"<weakness>","evidence":"<evidence>"}],"questions":[{"question":"<question>","motivation":"<why it matters>"}],"scores":{"correctness":"<1-5>","novelty":"<1-5>","recommendation":"<accept|borderline|reject>","confidence":"<1-5>"}}';

const transcript = '=== Reader ===\n' + (ctx.reader_summary || '') + '\n\n=== Critic ===\n' + (ctx.critic_points || '') + '\n\n=== Auditor ===\n' + (ctx.auditor_feedback || '');

const data = await this.helpers.request({
  method: 'POST',
  uri: 'https://api.openai.com/v1/chat/completions',
  headers: { 'Authorization': 'Bearer ' + apiKey },
  body: {
    model: 'gpt-4o',
    max_tokens: 1000,
    messages: [
      { role: 'system', content: 'You are a senior editor writing a peer review of the paper. Output only valid JSON matching this schema: ' + schema + ' The review must be about the paper itself, not about missing context or about the quality of the critique. Every weakness must be grounded in specific content from the paper text or summary. Do not include generic fallback complaints like unclear novelty, weak methodology, or reproducibility concerns unless the transcript ties them to concrete details. Remove unsupported points instead of keeping them vague. Prefer fewer high-quality weaknesses over generic ones. No markdown fences, no commentary.' },
      { role: 'user', content: 'Paper title: ' + (ctx.title || '') + '\n\nPaper text:\n' + paperText + '\n\nFull debate transcript:\n\n' + transcript + '\n\nProduce the final structured review JSON.' }
    ]
  },
  json: true
});

let rawOutput = data.choices[0].message.content.trim();
if (rawOutput.startsWith('```')) {
  rawOutput = rawOutput.split('```')[1];
  if (rawOutput.startsWith('json')) rawOutput = rawOutput.slice(4);
}

let structured;
try {
  structured = JSON.parse(rawOutput);
} catch (e) {
  structured = {
    summary: ctx.reader_summary || '',
    strengths: [],
    weaknesses: [],
    questions: [],
    scores: {
      correctness: '3',
      novelty: '3',
      recommendation: 'borderline',
      confidence: '2'
    },
    raw: rawOutput
  };
}

return [{ json: { paper_id: ctx.paper_id, title: ctx.title, output: structured } }];
